  params.append('mode', mode || 'payment');
  params.append('success_url', success_url);
  params.append('cancel_url', cancel_url);

  if (customer_email) params.append('customer_email', customer_email);

  line_items.forEach((item, index) => {
    if (item.price) {
      params.append(`line_items[${index}][price]`, item.price);
    } else {
      if (item.name) params.append(`line_items[${index}][price_data][product_data][name]`, item.name);
      if (item.description) params.append(`line_items[${index}][price_data][product_data][description]`, item.description);
      if (item.amount) params.append(`line_items[${index}][price_data][unit_amount]`, String(item.amount));
      if (item.currency) params.append(`line_items[${index}][price_data][currency]`, item.currency);
    }
    params.append(`line_items[${index}][quantity]`, String(item.quantity || 1));
  });

  if (metadata && typeof metadata === 'object') {
    Object.entries(metadata).forEach(([key, value]) => {
      params.append(`metadata[${key}]`, String(value));
    });
  }

  return await stripeRequest('POST', '/v1/checkout/sessions', params, env, corsHeaders);
