async function handleStripeWebhook(request, env, corsHeaders) {
  const signature = request.headers.get('stripe-signature');
  if (!signature) {
    return jsonResponse(400, { error: 'Missing Stripe signature' }, corsHeaders);
  }

  const rawBody = await request.text();

  // Verify webhook signature if secret is configured
  if (env.STRIPE_WEBHOOK_SECRET) {
    const isValid = await verifyStripeSignature(rawBody, signature, env.STRIPE_WEBHOOK_SECRET);
    if (!isValid) {
      console.error('Invalid Stripe webhook signature');
      return jsonResponse(400, { error: 'Invalid signature' }, corsHeaders);
    }
  }

  let event;
  try {
    event = JSON.parse(rawBody);
  } catch {
    return jsonResponse(400, { error: 'Invalid JSON' }, corsHeaders);
  }

  console.log(`Stripe webhook received: ${event.type} (${event.id})`);

  // Process different event types
  switch (event.type) {
    case 'payment_intent.succeeded':
      console.log(`Payment succeeded: ${event.data.object.id}, amount: ${event.data.object.amount}`);
      // Add your business logic here (e.g., fulfill order, update database via external API)
      break;

    case 'payment_intent.payment_failed':
      console.log(`Payment failed: ${event.data.object.id}, error: ${event.data.object.last_payment_error?.message}`);
      break;

    case 'checkout.session.completed':
      console.log(`Checkout completed: ${event.data.object.id}`);
      break;

    case 'customer.subscription.created':
    case 'customer.subscription.updated':
    case 'customer.subscription.deleted':
      console.log(`Subscription ${event.type}: ${event.data.object.id}`);
      break;

    case 'charge.refunded':
      console.log(`Charge refunded: ${event.data.object.id}`);
      break;

    default:
      console.log(`Unhandled event type: ${event.type}`);
  }

  return jsonResponse(200, { received: true, type: event.type }, corsHeaders);
}

// ==================== Stripe Signature Verification ====================

async function verifyStripeSignature(payload, signatureHeader, secret) {
  try {
    const pairs = signatureHeader.split(',').reduce((acc, item) => {
      const [key, value] = item.split('=');
      acc[key.trim()] = value;
      return acc;
    }, {});

    const timestamp = pairs['t'];
    const signature = pairs['v1'];

    if (!timestamp || !signature) return false;

    // Check timestamp tolerance (5 minutes)
    const currentTime = Math.floor(Date.now() / 1000);
    if (Math.abs(currentTime - parseInt(timestamp)) > 300) {
      console.error('Stripe webhook timestamp too old');
      return false;
    }

    const signedPayload = `${timestamp}.${payload}`;
    const encoder = new TextEncoder();

    const key = await crypto.subtle.importKey(
      'raw',
      encoder.encode(secret),
      { name: 'HMAC', hash: 'SHA-256' },
      false,
      ['sign']
    );

    const signatureBytes = await crypto.subtle.sign('HMAC', key, encoder.encode(signedPayload));
    const expectedSignature = Array.from(new Uint8Array(signatureBytes))
      .map(b => b.toString(16).padStart(2, '0'))
      .join('');

    return secureCompareStrings(expectedSignature, signature);
  } catch (err) {
    console.error('Signature verification error:', err.message);
    return false;
  }
}

function secureCompareStrings(a, b) {
  if (a.length !== b.length) return false;
  let result = 0;
  for (let i = 0; i < a.length; i++) {
    result |= a.charCodeAt(i) ^ b.charCodeAt(i);
  }
  return result === 0;
}

// ==================== Stripe Request Helper ====================

async function stripeRequest(method, path, params, env, corsHeaders) {
  const baseUrl = 'https://api.stripe.com';
  let url = `${baseUrl}${path}`;

  const options = {
    method,
    headers: {
      'Authorization': `Bearer ${env.STRIPE_SECRET_KEY}`,
      'Stripe-Version': '2023-10-16',
    },
  };

  if (method === 'POST' && params) {
    options.headers['Content-Type'] = 'application/x-www-form-urlencoded';
    options.body = params.toString();
  }

  try {
    const response = await fetchWithRetry(url, options);
    const data = await response.json();

    if (!response.ok) {
      console.error('Stripe API error:', response.status, JSON.stringify(data));

      const statusMap = {
        400: 400,
        401: 502,
        402: 402,
        404: 404,
        409: 409,
        429: 429,
      };

      const clientStatus = statusMap[response.status] || (response.status >= 500 ? 502 : 400);

      return jsonResponse(clientStatus, {
        error: data.error?.message || 'Stripe API error',
        type: data.error?.type,
        code: data.error?.code,
        decline_code: data.error?.decline_code,
      }, corsHeaders);
    }

    return jsonResponse(200, { success: true, data }, corsHeaders);

  } catch (err) {
    console.error('Stripe request failed:', err.message);
    return jsonResponse(502, {
      error: 'Failed to connect to payment service',
      message: err.message,
    }, corsHeaders);
  }
}

// ==================== Utility Functions ====================

async function fetchWithRetry(url, options, maxRetries = 2) {
  let lastError;

  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      const response = await fetch(url, options);

      // Only retry on 5xx errors or network issues
      if (response.status >= 500 && attempt < maxRetries) {
        const delay = Math.min(1000 * Math.pow(2, attempt), 4000);
        await new Promise(resolve => setTimeout(resolve, delay));
        continue;
      }

      // Don't retry on rate limits for idempotent safety
      return response;

    } catch (err) {
      lastError = err;
      if (attempt < maxRetries) {
        const delay = Math.min(1000 * Math.pow(2, attempt), 4000);
        await new Promise(resolve => setTimeout(resolve, delay));
      }
    }
  }

  throw lastError || new Error('Request failed after retries');
}

function jsonResponse(status, body, corsHeaders = {}) {
  return new Response(JSON.stringify(body), {
    status,
    headers: {
      'Content-Type': 'application/json',
      'X-Request-Id': crypto.randomUUID(),
      ...corsHeaders,
    },
  });
}